Given your stack (Kotlin, gRPC internal, REST external, PostgreSQL), here's the simplest approach:

**REST endpoint** for external merchant-facing, **gRPC** for internal calls from account-service.

```kotlin
// MerchantBankAccountVerificationService.kt

@GrpcService
class MerchantBankAccountVerificationService(
    private val accountServiceClient: AccountServiceGrpcClient,
    private val verificationRepository: VerificationRepository
) : MerchantVerificationGrpcKt.MerchantVerificationCoroutineImplBase() {

    override suspend fun verifyBankAccount(
        request: VerifyBankAccountRequest
    ): VerifyBankAccountResponse {
        // 1. Check merchant exists via account-service (gRPC)
        val merchant = accountServiceClient.getMerchant(request.merchantId)
            ?: throw StatusException(Status.NOT_FOUND)

        // 2. Micro-deposit verification (two small deposits, merchant confirms amounts)
        val verification = verificationRepository.save(
            BankAccountVerification(
                merchantId = request.merchantId,
                routingNumber = request.routingNumber,
                accountNumberHash = hash(request.accountNumber),
                accountNumberLast4 = request.accountNumber.takeLast(4),
                status = VerificationStatus.PENDING_MICRO_DEPOSITS,
                createdAt = Instant.now()
            )
        )

        // 3. Kick off micro-deposits async via Kafka
        kafkaTemplate.send(
            "payment.verification.initiated",
            VerificationInitiated(verification.id, request.merchantId)
        )

        return verifyBankAccountResponse {
            verificationId = verification.id.toString()
            status = PENDING_MICRO_DEPOSITS
        }
    }
}
```

